import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.*;

class CSVFormatTest {

    @Test
    void testIsQuoteCharacterSet_whenQuoteCharacterIsNotNull() throws Exception {
        // Create CSVFormat instance with quoteCharacter set (using DEFAULT)
        CSVFormat format = CSVFormat.DEFAULT;
        // Use reflection to invoke isQuoteCharacterSet
        boolean result = (boolean) CSVFormat.class.getMethod("isQuoteCharacterSet").invoke(format);
        assertTrue(result);
    }

    @Test
    void testIsQuoteCharacterSet_whenQuoteCharacterIsNull() throws Exception {
        // Create CSVFormat instance with quoteCharacter null using withQuote(null)
        CSVFormat format = CSVFormat.DEFAULT.withQuote((Character) null);
        // Use reflection to invoke isQuoteCharacterSet
        boolean result = (boolean) CSVFormat.class.getMethod("isQuoteCharacterSet").invoke(format);
        assertFalse(result);
    }
}
